const DEBUG = new URLSearchParams(location.search).has('debug');
function debugLog(...args) {
  if (!DEBUG) return;
  const line = args.map(a => {
    if (a instanceof Error) return a.stack || a.message;
    if (typeof a === 'string') return a;
    try { return JSON.stringify(a, null, 2); } catch { return String(a); }
  }).join(' ');
  console.log('[debug]', ...args);
  const panel = document.getElementById('debug-panel');
  const pre = document.getElementById('debug-log');
  if (panel && pre) {
    panel.style.display = 'block';
    pre.textContent += (pre.textContent ? '\n' : '') + line;
  }
}
if (DEBUG) {
  const panel = document.getElementById('debug-panel');
  if (panel) panel.style.display = 'block';
  debugLog('debug enabled', { href: location.href, origin: location.origin });
  window.addEventListener('error', (e) => {
    debugLog('window.error', { message: e.message, filename: e.filename, lineno: e.lineno, colno: e.colno });
  });
  window.addEventListener('unhandledrejection', (e) => {
    const reason = e.reason instanceof Error ? (e.reason.stack || e.reason.message) : e.reason;
    debugLog('unhandledrejection', { reason });
  });
}

const memoryStorage = (() => {
  const store = new Map();
  return {
    getItem: (key) => (store.has(key) ? store.get(key) : null),
    setItem: (key, value) => { store.set(key, String(value)); },
    removeItem: (key) => { store.delete(key); },
  };
})();

function canUseLocalStorage() {
  try {
    const k = '__vestiga_ls_test__';
    window.localStorage.setItem(k, '1');
    window.localStorage.removeItem(k);
    return true;
  } catch {
    return false;
  }
}

const localStorageOk = canUseLocalStorage();
const supabaseStorage = {
  getItem: (key) => {
    if (localStorageOk) {
      try { return window.localStorage.getItem(key); } catch { /* fall through */ }
    }
    return memoryStorage.getItem(key);
  },
  setItem: (key, value) => {
    if (localStorageOk) {
      try { window.localStorage.setItem(key, value); return; } catch { /* fall through */ }
    }
    memoryStorage.setItem(key, value);
  },
  removeItem: (key) => {
    if (localStorageOk) {
      try { window.localStorage.removeItem(key); return; } catch { /* fall through */ }
    }
    memoryStorage.removeItem(key);
  },
};

