async function doAuth() {
  if (!db) { showAuthErr(supabaseUnavailableMessage()); return; }
  const email = document.getElementById('auth-email').value.trim();
  const pass = document.getElementById('auth-pass').value;
  const btn = document.getElementById('auth-btn');
  if (!email || !pass) { showAuthErr('Please fill in email and password.'); return; }
  btn.disabled = true; btn.textContent = 'Please wait...';
  if (currentAuthTab === 'signin') {
    const { error } = await db.auth.signInWithPassword({ email, password: pass });
    debugLog('signInWithPassword', { email, ok: !error, error: error?.message });
    if (error) { showAuthErr(error.message); btn.disabled=false; btn.textContent='Sign In'; return; }
  } else {
    const displayName = document.getElementById('auth-name').value.trim();
    if (displayName) setStoredDisplayName(displayName);
    const { error } = await db.auth.signUp({ email, password: pass });
    debugLog('signUp', { email, ok: !error, error: error?.message });
    if (error) { showAuthErr(error.message); btn.disabled=false; btn.textContent='Create Account'; return; }
    document.getElementById('auth-success').style.display = 'block';
    btn.disabled = false;
    btn.textContent = 'Sign In';
    switchTab('signin');
  }
}

