function initSiteImageUpload() {
  const fileInput = document.getElementById('s-img-file');
  const preview = document.getElementById('s-img-preview');
  const previewImg = document.getElementById('s-img-preview-img');
  const meta = document.getElementById('s-img-preview-meta');
  if (!fileInput || !preview || !previewImg || !meta) return;

  fileInput.addEventListener('change', async () => {
    const f = fileInput.files && fileInput.files[0] ? fileInput.files[0] : null;
    if (!f) {
      uploadedSiteImageFile = null;
      if (uploadedSiteImagePreviewUrl) {
        try { URL.revokeObjectURL(uploadedSiteImagePreviewUrl); } catch {}
      }
      uploadedSiteImagePreviewUrl = '';
      preview.style.display = 'none';
      updateStoryMainImageFromData();
      return;
    }
    const maxBytes = 3 * 1024 * 1024; // keep localStorage and DB inserts sane for demos
    if (f.size > maxBytes) {
      fileInput.value = '';
      uploadedSiteImageFile = null;
      if (uploadedSiteImagePreviewUrl) {
        try { URL.revokeObjectURL(uploadedSiteImagePreviewUrl); } catch {}
      }
      uploadedSiteImagePreviewUrl = '';
      preview.style.display = 'none';
      alert('Please choose an image under 3MB for this front-end demo.');
      return;
    }
    try {
      if (uploadedSiteImagePreviewUrl) {
        try { URL.revokeObjectURL(uploadedSiteImagePreviewUrl); } catch {}
      }
      uploadedSiteImageFile = f;
      uploadedSiteImagePreviewUrl = URL.createObjectURL(f);
      previewImg.src = uploadedSiteImagePreviewUrl;
      meta.textContent = `${f.name} · ${(f.size / 1024).toFixed(0)} KB`;
      preview.style.display = 'block';
      updateStoryMainImageFromData();
    } catch (e) {
      uploadedSiteImageFile = null;
      if (uploadedSiteImagePreviewUrl) {
        try { URL.revokeObjectURL(uploadedSiteImagePreviewUrl); } catch {}
      }
      uploadedSiteImagePreviewUrl = '';
      preview.style.display = 'none';
      alert((e && e.message) ? e.message : 'Could not read image.');
    }
  });
}

async function uploadSiteImageToStorage(file) {
  if (!db?.storage) throw new Error('Supabase Storage is not available in this client.');
  const safeName = (file.name || 'upload').replace(/[^a-zA-Z0-9._-]+/g, '-');
  const folder = currentUser?.id ? String(currentUser.id) : 'anon';
  const path = `${folder}/${Date.now()}-${safeName}`;

  const { error } = await db.storage.from(SITE_IMAGES_BUCKET).upload(path, file, {
    contentType: file.type || 'application/octet-stream',
    upsert: false,
  });
  if (error) throw error;

  const { data } = db.storage.from(SITE_IMAGES_BUCKET).getPublicUrl(path);
  const publicUrl = data?.publicUrl || '';
  if (!publicUrl) throw new Error('Could not get a public URL for the uploaded image.');
  return publicUrl;
}

// DUPLICATE CHECK
let dupeTimer;
async function checkDupe() {
  clearTimeout(dupeTimer);
  dupeTimer = setTimeout(async () => {
    const name = normalizeText(document.getElementById('s-name').value);
    const loc = normalizeText(document.getElementById('s-loc').value);
    if (name.length < 3) { document.getElementById('dupe-warn').classList.remove('show'); return; }

    // Find closest approved match by (name + location) similarity.
    let best = null;
    let bestScore = 0;
    for (const s of allSites) {
      const sName = normalizeText(s.name);
      const sLoc = normalizeText(s.location);
      const nameScore = diceCoeff(name, sName);
      const locScore = loc ? diceCoeff(loc, sLoc) : 0.6; // if user didn't type location yet, don't penalize too hard
      const score = 0.7 * nameScore + 0.3 * locScore;
      if (score > bestScore) { bestScore = score; best = s; }
    }
    const warn = document.getElementById('dupe-warn');
    if (best && bestScore >= 0.78) {
      warn.innerHTML = `⚠️ <strong>${esc(best.name)}</strong> in <strong>${esc(best.location)}</strong> is already listed on Vestiga. Please check the directory before submitting.`;
      warn.classList.add('show');
    } else {
      warn.classList.remove('show');
    }
  }, 500);
}

async function submitSite() {
  if (!db) { alert(supabaseUnavailableMessage()); return; }
  debugLog('submitSite:start', { currentUserId: currentUser?.id, email: currentUser?.email });
  const name = document.getElementById('s-name').value.trim();
  const loc = document.getElementById('s-loc').value.trim();
  const desc = document.getElementById('s-desc').value.trim();
  if (!name || !loc) { alert('Site name and location are required.'); return; }
  if (!desc || desc.length < 30) { alert('Please add a description of at least 30 characters. This helps moderators verify it\'s a real heritage site.'); return; }
  const phone = document.getElementById('s-phone').value.trim();
  const email = document.getElementById('s-email').value.trim();
  const website = document.getElementById('s-web').value.trim();
  const maps_url = document.getElementById('s-maps').value.trim();
  if (!phone && !email && !website && !maps_url) {
    alert('Please add at least one verification/contact field (Google Maps link, website, phone, or email). This helps prevent fake submissions.');
    return;
  }
  if (document.getElementById('dupe-warn').classList.contains('show')) {
    if (!confirm('A similar site may already exist. Submit anyway?')) return;
  }
  const btn = document.getElementById('modal-btn');
  btn.disabled = true; btn.textContent = 'Submitting...';
  const urlInput = document.getElementById('s-img').value.trim();
  let chosenImage = urlInput || null;
  try {
    if (uploadedSiteImageFile) {
      chosenImage = await uploadSiteImageToStorage(uploadedSiteImageFile);
    }
  } catch (e) {
    alert('Could not upload image. Submit without an image, or try again.\n' + ((e && e.message) ? e.message : String(e)));
    btn.disabled = false; btn.textContent = 'Submit for Review';
    return;
  }
  const payload = {
    name, location: loc, description: desc,
    phone: phone || null,
    email: email || null,
    website: website || null,
    maps_url: maps_url || null,
    image_url: chosenImage,
    submitted_by: getDisplayName() || currentUser?.email?.split('@')[0] || null,
    user_id: currentUser?.id || null,
    status: 'pending'
  };
  debugLog('submitSite:payload', payload);
  const { error } = await db.from('sites').insert([payload]);
  debugLog('submitSite:insertResult', { ok: !error, error: error?.message });
  if (error) { alert('Could not submit. Try again.\n'+error.message); btn.disabled=false; btn.textContent='Submit for Review'; return; }

  if (chosenImage) {
    latestSubmittedImageUrl = chosenImage;
    updateStoryMainImageFromData();
  }

  if (currentUser?.id) {
    const res = await db.from('sites')
      .select('id,status,user_id,created_at,name,location')
      .eq('user_id', currentUser.id)
      .order('created_at', { ascending: false })
      .limit(1);
    debugLog('submitSite:readBack', { ok: !res.error, error: res.error?.message, data: res.data?.[0] });
    if (res.error) {
      debugLog('submitSite:readBackHint', 'Read-back blocked (likely RLS). The row may exist but you cannot SELECT it.');
    } else if (!res.data || !res.data.length) {
      debugLog('submitSite:readBackHint', 'Insert succeeded but SELECT returned 0 rows. This usually means your RLS SELECT policy does not allow the submitting user to read their own rows (add a policy like: user_id = auth.uid()).');
    } else if (res.data?.[0] && res.data[0].status !== 'pending') {
      debugLog('submitSite:statusNote', `Inserted row status is "${res.data[0].status}" (not "pending"), so admin "pending" list will be empty.`);
    }
  }
  document.getElementById('modal-form').style.display = 'none';
  document.getElementById('modal-success').style.display = 'block';
}

// ── DATA ──
async function loadAll() {
  if (!db) {
    allSites = [];
    ratingMap = {};
    const g = document.getElementById('sites-grid');
    if (g) g.innerHTML = `<div style="font-size:14px;color:var(--ash);padding:1rem 0;line-height:1.6;">${supabaseUnavailableMessage()}</div>`;
    return;
  }
  try {
    const { data: sites, error: sitesError } = await db.from('sites').select('*').eq('status', 'approved').order('created_at', { ascending: false });
    if (sitesError) throw sitesError;
    allSites = sites || [];

    const { data: ratings, error: ratingsError } = await db.from('ratings').select('site_id,rating');
    if (ratingsError) throw ratingsError;
    ratingMap = {};
    (ratings || []).forEach(r => { if (!ratingMap[r.site_id]) ratingMap[r.site_id] = []; ratingMap[r.site_id].push(r.rating); });

    const { data: pledges, error: pledgesError } = await db.from('pledges').select('id', { count: 'exact' });
    if (pledgesError) throw pledgesError;
    const pc = pledges ? pledges.length : 0;
    const pledgeCount = document.getElementById('pledge-count'); if (pledgeCount) pledgeCount.textContent = pc;
    const statSites = document.getElementById('stat-sites'); if (statSites) statSites.textContent = allSites.length;
    const statPledges = document.getElementById('stat-pledges'); if (statPledges) statPledges.textContent = pc;
    const statRatings = document.getElementById('stat-ratings'); if (statRatings) statRatings.textContent = Object.values(ratingMap).reduce((a, b) => a + b.length, 0);
    renderSites(allSites);
    updateStoryMainImageFromData();
  } catch (e) {
    allSites = [];
    ratingMap = {};
    const msg = (e && e.message) ? e.message : String(e);
    const g = document.getElementById('sites-grid');
    if (g) g.innerHTML = `<div style="font-size:14px;color:var(--ash);padding:1rem 0;line-height:1.6;">Could not load sites from Supabase.<br><span style="font-size:12px;opacity:.9">${esc(msg)}</span></div>`;
  }
}

function starsHtml(avg) { return[1,2,3,4,5].map(i=>`<span class="star${i<=Math.round(avg)?'':' e'}">★</span>`).join(''); }

function renderSites(sites) {
  const g = document.getElementById('sites-grid');
  if (!g) return;
  if (!sites.length) { g.innerHTML='<div class="empty"><div class="ico">🏛️</div><p>No approved sites yet.<br>Submit the first one!</p></div>'; return; }
  g.innerHTML = sites.map(s => {
    const rs = ratingMap[s.id]||[];
    const avg = rs.length ? rs.reduce((a,b)=>a+b,0)/rs.length : 0;
    const href = `site.html?id=${encodeURIComponent(s.id)}`;
    const img = s.image_url ? `<img src="${esc(s.image_url)}" alt="${esc(s.name)}" loading="lazy" onerror="this.parentElement.innerHTML='🏛️'">` : '🏛️';
    const links=[];
    if(s.maps_url) links.push(`<a class="site-link" href="${esc(s.maps_url)}" target="_blank" rel="noopener">📍 Maps</a>`);
    if(s.phone) links.push(`<a class="site-link" href="tel:${esc(s.phone)}">📞 Call</a>`);
    if(s.email) links.push(`<a class="site-link" href="mailto:${esc(s.email)}">✉️ Email</a>`);
    if(s.website) links.push(`<a class="site-link" href="${esc(s.website)}" target="_blank" rel="noopener">🌐 Website</a>`);
    return `<div class="site-card" id="card-${s.id}">
      <a class="site-card-link" href="${href}" aria-label="Open ${esc(s.name)} details">
        <div class="site-card-img">${img}</div>
      </a>
      <div class="site-card-body">
        <div class="site-card-name"><a href="${href}" class="site-card-name-link">${esc(s.name)}</a></div>
        <div class="site-card-loc">📍 ${esc(s.location)}</div>
        <div class="stars-row"><div class="stars" id="st-${s.id}">${starsHtml(avg)}</div><span class="rcount" id="rc-${s.id}">${rs.length ? avg.toFixed(1)+' ('+rs.length+')' : 'No ratings yet'}</span></div>
        ${s.description?`<div class="site-desc">${esc(s.description)}</div>`:''}
      </div>
      ${links.length?`<div class="site-links">${links.join('')}</div>`:''}
      <div class="site-footer">
        <span class="added-by">${s.submitted_by?'Added by '+esc(s.submitted_by):''}</span>
        <button class="rate-btn" onclick="toggleRate(${s.id}, '${esc(s.name)}')">Rate & Review ★</button>
      </div>
      <div class="rate-panel" id="rp-${s.id}">
        <div class="rate-lbl">Your rating for ${esc(s.name)}:</div>
        <div class="rstar-row" id="rs-${s.id}">${[1,2,3,4,5].map(i=>`<button class="rstar" data-val="${i}" onclick="pickStar(${s.id},${i})">★</button>`).join('')}</div>
        <input class="review-input" id="rname-${s.id}" type="text" placeholder="Your name (optional)" maxlength="40"/>
        <textarea class="review-input" id="rtxt-${s.id}" rows="3" placeholder="Write a review... (optional) What was your experience like?"></textarea>
        <div style="display:flex;align-items:center;flex-wrap:wrap;gap:8px;">
          <button class="rate-submit" onclick="doRate(${s.id})">Submit Review</button>
          <span class="rate-ok" id="rok-${s.id}">Thanks! ✓</span>
        </div>
        <div class="reviews-list" id="rvlist-${s.id}"></div>
      </div>
    </div>`;
  }).join('');
  // load reviews for open panels (none open yet but prep the fn)
}

function filterSites() {
  const q = document.getElementById('search-input').value.toLowerCase().trim();
  renderSites(q ? allSites.filter(s=>s.name.toLowerCase().includes(q)||s.location.toLowerCase().includes(q)) : allSites);
}

const selRatings = {};
function toggleRate(id, name) {
  const panel = document.getElementById('rp-'+id);
  const isOpen = panel.classList.contains('open');
  // close all panels first
  document.querySelectorAll('.rate-panel.open').forEach(p=>p.classList.remove('open'));
  if (!isOpen) {
    panel.classList.add('open');
    loadReviews(id);
  }
}

function pickStar(sid, val) {
  selRatings[sid] = val;
  document.querySelectorAll(`#rs-${sid} .rstar`).forEach(b => b.classList.toggle('on', parseInt(b.dataset.val)<=val));
}

async function doRate(sid) {
  if (!db) { alert(supabaseUnavailableMessage()); return; }
  const rating = selRatings[sid];
  if (!rating) { alert('Please pick a star rating first.'); return; }
  const review = document.getElementById('rtxt-'+sid).value.trim() || null;
  const reviewer_name = document.getElementById('rname-'+sid).value.trim() || getDisplayName() || null;
  const { error } = await db.from('ratings').insert([{ site_id:sid, rating, review, reviewer_name }]);
  if (error) { alert('Could not submit. Try again.'); return; }
  document.getElementById('rok-'+sid).style.display = 'inline';
  document.querySelectorAll(`#rs-${sid} .rstar`).forEach(b => b.style.pointerEvents='none');
  document.getElementById('rtxt-'+sid).disabled = true;
  document.getElementById('rname-'+sid).disabled = true;
  // refresh stars
  const { data } = await db.from('ratings').select('rating').eq('site_id',sid);
  if (data) {
    ratingMap[sid] = data.map(x=>x.rating);
    const avg = ratingMap[sid].reduce((a,b)=>a+b,0)/ratingMap[sid].length;
    document.getElementById('st-'+sid).innerHTML = starsHtml(avg);
    document.getElementById('rc-'+sid).textContent = avg.toFixed(1)+' ('+ratingMap[sid].length+')';
    document.getElementById('stat-ratings').textContent = Object.values(ratingMap).reduce((a,b)=>a+b.length,0);
  }
  loadReviews(sid);
}

async function loadReviews(sid) {
  if (!db) return;
  const { data } = await db.from('ratings').select('*').eq('site_id',sid).order('created_at',{ascending:false}).limit(10);
  const el = document.getElementById('rvlist-'+sid);
  if (!data || !data.length) { el.innerHTML=''; return; }
  const withReview = data.filter(r=>r.review);
  if (!withReview.length) { el.innerHTML=''; return; }
  el.innerHTML = `<div style="font-size:11px;font-weight:500;letter-spacing:0.08em;text-transform:uppercase;color:var(--ash);margin-bottom:6px;">Reviews</div>` +
    withReview.map(r=>`<div class="review-item">
      <div class="review-stars">${'★'.repeat(r.rating)}${'☆'.repeat(5-r.rating)}</div>
      ${r.reviewer_name?`<div class="review-name">${esc(r.reviewer_name)}</div>`:''}
      <div class="review-text">${esc(r.review)}</div>
      <div class="review-ago">${ago(r.created_at)}</div>
    </div>`).join('');
}

// ── PLEDGES ──
async function loadPledges() {
  if (!db) return;
  const wall = document.getElementById('pledge-wall');
  const countEl = document.getElementById('pledge-count');
  if (!wall || !countEl) return;
  const { data } = await db.from('pledges').select('*').order('created_at',{ascending:false}).limit(20);
  if (!data) return;
  countEl.textContent = data.length;
  if (!data.length) { wall.innerHTML='<div style="font-size:13px;color:rgba(251,247,240,0.3);padding:.5rem 0;">No pledges yet.</div>'; return; }
  wall.innerHTML = data.map(p => {
    const ini = p.name.trim().split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);
    return `<div class="pledge-item"><div class="p-avatar">${ini}</div><div><div class="p-name">${esc(p.name)}</div><div class="p-text">${esc(p.pledge)} · ${ago(p.created_at)}</div></div></div>`;
  }).join('');
}

async function submitPledge() {
  if (!db) { alert(supabaseUnavailableMessage()); return; }
  const name = document.getElementById('p-name').value.trim();
  const pledge = document.getElementById('p-pledge').value;
  if (!name||!pledge) { alert('Please fill in your name and pick a pledge.'); return; }
  const btn = document.getElementById('p-btn');
  btn.disabled=true; btn.textContent='Saving...';
  const { error } = await db.from('pledges').insert([{name,pledge}]);
  if (error) { alert('Something went wrong.'); btn.disabled=false; btn.textContent='Leave My Mark'; return; }
  btn.style.display='none';
  document.getElementById('p-ok').style.display='block';
  loadPledges();
}
if (db && typeof db.channel === 'function') {
  db.channel('pledges').on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'pledges' }, loadPledges).subscribe();
}

// ── UTILS ──
function esc(s){if(!s)return'';return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function ago(ts){const d=Math.floor((Date.now()-new Date(ts))/1000);if(d<60)return'just now';if(d<3600)return Math.floor(d/60)+'m ago';if(d<86400)return Math.floor(d/3600)+'h ago';return Math.floor(d/86400)+'d ago';}
function normalizeText(s){return (s||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim();}
function bigrams(s){const r=[];for(let i=0;i<s.length-1;i++)r.push(s.slice(i,i+2));return r;}
function diceCoeff(a,b){
  if(!a||!b) return 0;
  if(a===b) return 1;
  if(a.length < 2 || b.length < 2) return 0;
  const aa=bigrams(a), bb=bigrams(b);
  const denom = aa.length + bb.length;
  if (!denom) return 0;
  const map=new Map(); aa.forEach(x=>map.set(x,(map.get(x)||0)+1));
  let inter=0;
  bb.forEach(x=>{const c=map.get(x)||0; if(c){inter++; map.set(x,c-1);}});
  return (2*inter)/denom;
}
const DISPLAY_NAME_KEY = 'vestiga_display_name';
function getStoredDisplayName(){try{return localStorage.getItem(DISPLAY_NAME_KEY)||'';}catch{return '';}}
function setStoredDisplayName(name){try{localStorage.setItem(DISPLAY_NAME_KEY, name);}catch{}}
function getDisplayName(){
  const n = getStoredDisplayName().trim();
  if (n) return n;
  const email = currentUser?.email || '';
  return email ? email.split('@')[0] : '';
}
function applyLogo(){
  const el = document.getElementById('nav-logo-img');
  if (!el || typeof LOGO_URL === 'undefined') return;
  // Some exports accidentally label JPEG bytes as PNG. Fix MIME if needed.
  const fixed = (LOGO_URL.startsWith('data:image/png;base64,/9j/'))
    ? LOGO_URL.replace('data:image/png', 'data:image/jpeg')
    : LOGO_URL;
  el.src = fixed;
  el.style.display = '';
}

function updateStoryMainImageFromData() {
  const imgEl = document.getElementById('story-main-img');
  const capEl = document.getElementById('story-main-cap');
  const wrap = imgEl?.closest('.story-media');
  if (!imgEl || !capEl || !wrap) return;

  const fromApproved = (allSites || []).find(s => s.image_url) || (allSites || [])[0];
  const usePreview = !!uploadedSiteImagePreviewUrl;
  const useLatest = !!latestSubmittedImageUrl;
  const src = latestSubmittedImageUrl || uploadedSiteImagePreviewUrl || fromApproved?.image_url || '';

  if (!src) {
    wrap.classList.remove('has-img');
    imgEl.removeAttribute('src');
    imgEl.alt = '';
    capEl.textContent = '';
    return;
  }

  wrap.classList.add('has-img');
  imgEl.src = src;
  imgEl.alt = useLatest
    ? 'Recently submitted site image'
    : (usePreview
      ? 'Selected site image (preview)'
      : (fromApproved?.name ? `Featured image: ${fromApproved.name}` : 'Featured site image'));
  capEl.textContent = useLatest
    ? 'Recently submitted image'
    : (usePreview
      ? 'Selected image preview'
      : (fromApproved?.name
        ? `Featured: ${fromApproved.name}${fromApproved.location ? ' · ' + fromApproved.location : ''}`
        : 'Featured community site'));
}



